tlVector2OffsetListChunk::tlVector2OffsetListChunk()
{
    Init();
}

tlVector2OffsetListChunk::tlVector2OffsetListChunk(const tlVector2OffsetListChunk& ch)
{
    Init();
    *this = ch;
}

tlVector2OffsetListChunk::~tlVector2OffsetListChunk()
{

    if(offsets != NULL){
        delete[] offsets;
    }
}

tlVector2OffsetListChunk::tlVector2OffsetListChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Animation::VertexAnim::OffsetList::VECTOR2);
    ident = Pure3D::Animation::VertexAnim::OffsetList::VECTOR2;

    tlFile* f = ch->GetFile();
    unsigned int i;

    version = f->GetLong();
    numoffsets = f->GetLong();
    param = f->GetLong();
    offsets = new tlUV[numoffsets];
    for(i = 0; i < numoffsets; i++)
    {
        offsets[i].Read(f);
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Animation::VertexAnim::OffsetList::VECTOR2);
    }
}

void
tlVector2OffsetListChunk::Init()
{
    ident = Pure3D::Animation::VertexAnim::OffsetList::VECTOR2;
    version = 0;
    numoffsets = 0;
    param = 0;
    offsets = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Animation::VertexAnim::OffsetList::VECTOR2);
    }
}

long 
tlVector2OffsetListChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( version );
    s += sizeof( numoffsets );
    s += sizeof( param );
    for(i = 0; i < (int)numoffsets; i++)
    {
        s += sizeof( offsets[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlVector2OffsetListChunk&
tlVector2OffsetListChunk::operator=(const tlVector2OffsetListChunk& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    version = a.version;
    numoffsets = a.numoffsets;
    param = a.param;
    if(offsets)
    {
        delete offsets;
    }
    offsets = new tlUV[numoffsets];
    for( i = 0; i < numoffsets ; i++ )
    {
        offsets[i] = a.offsets[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlVector2OffsetListChunk::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlVector2OffsetListChunk* aptr = dynamic_cast<const tlVector2OffsetListChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(version == aptr->version))
    {
        return false;
    }
    if(!(numoffsets == aptr->numoffsets))
    {
        return false;
    }
    if(!(param == aptr->param))
    {
        return false;
    }
    for(i = 0; i < numoffsets; i++)
    {
        if(!(offsets[i] == aptr->offsets[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

