void
tlOffsetIndexListChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

    unsigned int i;
        f->PutLong(version);
        f->PutLong(numindex);
    for(i = 0; i < numindex ; i++)
    {
        f->PutLong(index[i]);
    }

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlOffsetIndexListChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{
    unsigned int i;

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlOffsetIndexListChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Version  = %ld\n",indent,"",version);
    printf("%*s  NumIndex = %ld\n",indent,"",numindex);
    printf("%*s  Index:\n",indent,"");
    for( i=0; i < numindex; i++)
    {
         printf("%*s    %d %ld\n",indent,"",i,index[i]);
    }

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlOffsetIndexListChunk::PrintFormatted(int indent)
{
    unsigned int i;
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  int   %12ld # Version \n",indent,"",version);
    printf("%*s  int   %12ld # NumIndex\n",indent,"",numindex);
    printf("%*s  repeat 1 int   # Index   \n",indent,"");
    for( i=0; i < numindex; i++)
    {
         printf("%*s    %12ld\n",indent,"",index[i]);
    }
    printf("%*s  endrepeat\n",indent,"");
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

