void 
tlOffsetIndexListChunk::SetIndex(unsigned long* val, int count)
{
    if(index)
    {
        delete[] index;
    }      
    unsigned long* newval = new unsigned long[count];
    for(int i = 0; i < count ; i++)
    {
        newval[i] = val[i];
    }
    index = newval;
}
